import { GoogleGenAI } from "@google/genai";
import { StudyConfig, Language, StudyType, KnowledgeLevel, ActivityLog } from "../types";

// Upgraded to Gemini 3.0 Flash for superior quality and speed
const modelName = "gemini-3-flash-preview";

const getToneAndStyle = (type: StudyType, level: KnowledgeLevel, isChinese: boolean) => {
  let tone = "";

  switch (type) {
    case StudyType.Sermon:
      tone = "ROLE: Expert Homiletician. TONE: Passionate, oral-focused, persuasive. Use 'we' language. STRUCTURE: Point-Illustration-Application.";
      break;
    case StudyType.Devotional:
      tone = "ROLE: Spiritual Director. TONE: Warm, contemplative, soul-stirring. Focus on spiritual formation and the heart.";
      break;
    case StudyType.Academic:
    case StudyType.Comprehensive:
      tone = "ROLE: Biblical Scholar. TONE: Rigorous, objective, technical. Engage original languages (Greek/Hebrew) and critical consensus.";
      break;
    case StudyType.Discussion:
      tone = "ROLE: Facilitator. TONE: Engaging, inquiry-based, dialogical. Focus on community application.";
      break;
  }

  if (level === KnowledgeLevel.Scholarly) {
    tone += " DEPTH: Maximum. Use technical jargon, cite specific schools of thought, and analyze linguistic nuances.";
  } else if (level === KnowledgeLevel.Beginner) {
    tone += " DEPTH: Introductory. Avoid unexplained technical terms. Use clear analogies.";
  }

  return tone;
};

export const generateTopic = async (passage: string, language: Language, apiKey: string): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey });
  const isChinese = language === Language.TraditionalChinese;

  const prompt = `
    Analyze the biblical passage: "${passage}".
    Generate 3 distinct, contemporary, and engaging theological themes or titles.
    Style: Catchy, existential, and editorially polished.
    Language: ${isChinese ? 'Traditional Chinese (繁體中文)' : 'English'}
    Format: JSON array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: { 
        temperature: 0.9, 
        responseMimeType: "application/json"
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Error generating topic:", error);
    return [];
  }
};

export const generateStudyGuide = async (
  config: StudyConfig, 
  apiKey: string,
  onLog: (log: ActivityLog) => void
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey });
  const isChinese = config.language === Language.TraditionalChinese;
  const toneInstruction = getToneAndStyle(config.studyType, config.knowledgeLevel, isChinese);

  const log = (
    en: string, 
    zh: string, 
    status: 'pending' | 'processing' | 'success' | 'error' = 'processing',
    detail?: string
  ) => {
    onLog({
      id: crypto.randomUUID(),
      timestamp: new Date(),
      label: { en, zh },
      status,
      detail
    });
  };

  const approachesString = config.approaches.map(id => {
    if (id === 'custom') return `Custom: ${config.customApproach}`;
    return id;
  }).join(', ');

  const systemInstruction = `
    You are an elite Biblical Scholar and Professional Content Designer.
    Target: "${config.passage}" | Topic: "${config.topic}"
    Context: ${config.studyType} for ${config.knowledgeLevel} level.
    Lenses: ${approachesString || 'Standard Exegesis'}
    Traditions: ${config.traditions.join(', ') || 'Ecumenical'}
    Language: ${isChinese ? 'Traditional Chinese' : 'English'}

    ${toneInstruction}

    CONSTRAINTS:
    - Use Markdown strictly.
    - Provide deep, high-value insights.
    - Target total word count: ~5,000-8,000 words across parts.
  `;

  try {
    log("Initializing Neural Engine", "正在初始化神經網路引擎", 'processing', `Model: ${modelName}`);

    const chat = ai.chats.create({
      model: modelName,
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    log("Kernel Connection Established", "內核連接已建立", 'success', "Latency: Optimized");

    const sections = [
      { 
        id: "intro",
        label: { en: "Contextual Framework", zh: "背景與架構分析" },
        prompt: `Generate Section 1: Introduction, Literary Context, and Socio-Historical Setting. Connect "${config.passage}" to "${config.topic}".`
      },
      { 
        id: "exegesis",
        label: { en: "Exegetical Deep-Dive", zh: "深層釋經與語意分析" },
        prompt: `Generate Section 2: Detailed Exegesis. If ${config.knowledgeLevel} is Scholarly, include Greek/Hebrew word studies. Engage ${approachesString}.`
      },
      { 
        id: "tradition",
        label: { en: "Historical Synthesis", zh: "歷史傳統與神學綜合" },
        prompt: `Generate Section 3: Synthesis with ${config.traditions.join(', ')} traditions. How has this been interpreted through the ages?`
      },
      { 
        id: "application",
        label: { en: "Existential Application", zh: "存在意義與實踐應用" },
        prompt: `Generate Section 4: Contemporary Implications, Application for ${config.studyType}, and Conclusion.`
      }
    ];

    let fullContent = "";

    for (const section of sections) {
      log(`Constructing ${section.label.en}`, `正在構建 ${section.label.zh}`, 'processing', "Analyzing cross-references...");
      const result = await chat.sendMessage({ message: section.prompt });
      const text = result.text || "";
      fullContent += "\n\n" + text;
      log(`${section.label.en} Finalized`, `${section.label.zh} 已完成`, 'success', `${text.length} characters synthesized.`);
    }

    log("Atomic Integrity Check Passed", "原子完整性檢查通過", 'success', "Compiling final document...");
    return fullContent.trim();

  } catch (error) {
    log("System Fault Detected", "偵測到系統故障", 'error', error instanceof Error ? error.message : "Network Protocol Failure");
    throw error;
  }
};

import { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from '@google/genai';
import Markdown from 'react-markdown';
import { Language } from '../types';

interface ChatSessionProps {
  contextContent: string;
  language: Language;
  onClose: () => void;
  apiKey: string;
}

interface Message {
  role: 'user' | 'model';
  text: string;
}

export const ChatSession: React.FC<ChatSessionProps> = ({ contextContent, language, onClose, apiKey }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const chatRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const isChinese = language === Language.TraditionalChinese;

  useEffect(() => {
    const initChat = async () => {
      if (!apiKey) return;
      const ai = new GoogleGenAI({ apiKey });

      const systemInstruction = `
        You are a PhD-level Theological Research Assistant.
        Report Context: """${contextContent.substring(0, 10000)}"""
        Tasks:
        1. Answer follow-ups based on the generated report.
        2. Expand using your internal scholarly database for deep theology.
        3. Maintain a tone of professional excellence.
        Language: ${isChinese ? 'Traditional Chinese' : 'English'}
      `;

      try {
        const chat = ai.chats.create({
          model: 'gemini-3-flash-preview',
          config: {
            systemInstruction,
            temperature: 0.7,
          }
        });
        chatRef.current = chat;
        const greeting = isChinese 
          ? "報告已生成。我是您的神學研究助理，針對上述內容或其原始語境，您有什麼需要更深入探討的嗎？"
          : "The analysis is complete. I am your theological research assistant. How can I further assist your inquiry into this text or its historical implications?";
        setMessages([{ role: 'model', text: greeting }]);
      } catch (error) {
        console.error("Chat init error:", error);
      }
    };
    initChat();
  }, [contextContent, isChinese, apiKey]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || !chatRef.current || isLoading) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const result = await chatRef.current.sendMessageStream({ message: userMsg });
      setMessages(prev => [...prev, { role: 'model', text: '' }]);
      let fullText = '';
      for await (const chunk of result) {
        fullText += (chunk as GenerateContentResponse).text || '';
        setMessages(prev => {
          const newMsgs = [...prev];
          newMsgs[newMsgs.length - 1] = { role: 'model', text: fullText };
          return newMsgs;
        });
      }
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Service Error: Connection interrupted." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-md animate-fade-in p-4">
      <div className="bg-white w-full max-w-3xl h-[85vh] rounded-2xl shadow-2xl overflow-hidden flex flex-col border border-white/20">
        <div className="bg-sage-600 p-5 flex justify-between items-center shadow-lg z-10 shrink-0">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-white/20 rounded-full flex items-center justify-center border border-white/30">
              <span className="text-xl">📜</span>
            </div>
            <div>
              <h3 className="text-xl font-serif font-bold text-white tracking-wide">Research Consultation</h3>
              <p className="text-sage-100 text-xs uppercase tracking-widest font-medium">Session: Scholarly AI Assistant</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full text-white transition-all">
            <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 bg-ivory space-y-6">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] rounded-2xl px-6 py-4 shadow-sm font-serif ${msg.role === 'user' ? 'bg-sage-600 text-white rounded-tr-none' : 'bg-white border border-stone-200 text-charcoal rounded-tl-none'}`}>
                <div className="prose prose-sm max-w-none leading-relaxed">
                  <Markdown>{msg.text}</Markdown>
                </div>
              </div>
            </div>
          ))}
          {isLoading && <div className="text-sage-400 italic text-sm animate-pulse px-2">Assistant is synthesizing response...</div>}
          <div ref={messagesEndRef} />
        </div>
        <div className="p-6 bg-white border-t border-stone-200">
          <div className="relative flex items-end gap-3">
            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Inquire further..."
              className="w-full p-4 pr-14 max-h-40 min-h-[60px] bg-stone-50 border border-stone-300 rounded-xl focus:ring-2 focus:ring-sage-500 outline-none resize-none transition-all font-serif"
              rows={1}
            />
            <button onClick={handleSend} disabled={!input.trim() || isLoading} className="absolute right-3 bottom-3 p-3 bg-sage-600 text-white rounded-xl hover:bg-sage-700 disabled:bg-stone-300 transition-all">
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import Markdown from 'react-markdown';
import { Language, ActivityLog } from '../types';
import { UI_TEXT } from '../constants';
import { ChatSession } from './ChatSession';

interface ResultDisplayProps {
  content: string;
  isGenerating: boolean;
  language: Language;
  logs: ActivityLog[];
  apiKey: string;
}

export const ResultDisplay: React.FC<ResultDisplayProps> = ({ content, isGenerating, language, logs, apiKey }) => {
  const [showChatSession, setShowChatSession] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const langKey = language === Language.English ? 'en' : 'zh';

  useEffect(() => {
    if (isGenerating && logsEndRef.current) {
      logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, isGenerating]);

  const handleCopy = async () => {
    await navigator.clipboard.writeText(content);
    alert(language === Language.English ? "Captured to clipboard." : "內容已存入剪貼簿。");
  };

  const handleDownloadWord = () => {
    if (!contentRef.current) return;
    const html = `<html><head><meta charset='utf-8'><style>body{font-family:'Times New Roman',serif;padding:20px;}</style></head><body>${contentRef.current.innerHTML}</body></html>`;
    const blob = new Blob(['\ufeff', html], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `SacredStudy_${new Date().toISOString().slice(0,10)}.doc`;
    link.click();
  };

  if (isGenerating) {
    return (
      <div className="bg-[#1a1a1a] rounded-xl border border-white/10 shadow-2xl overflow-hidden font-mono text-[13px] max-w-3xl mx-auto my-12 animate-fade-in ring-1 ring-white/5">
        <div className="bg-white/5 p-4 border-b border-white/10 flex justify-between items-center">
          <div className="flex space-x-2">
            <div className="w-2.5 h-2.5 rounded-full bg-red-500/40"></div>
            <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/40"></div>
            <div className="w-2.5 h-2.5 rounded-full bg-green-500/40"></div>
          </div>
          <div className="text-white/40 text-[10px] uppercase tracking-[0.2em] font-bold">
            Live Synthesis Terminal
          </div>
        </div>
        <div className="p-8 h-[450px] overflow-y-auto space-y-4 scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent">
          {logs.map((log) => (
            <div key={log.id} className="flex gap-4 animate-log-entry border-l border-white/5 pl-4 ml-2">
              <span className="text-white/20 shrink-0 select-none">
                [{log.timestamp.toLocaleTimeString([], { hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit' })}]
              </span>
              <div className="flex-1">
                <div className="flex items-center gap-3">
                  <span className={`
                    text-[10px] font-bold px-1.5 py-0.5 rounded
                    ${log.status === 'success' ? 'bg-green-500/20 text-green-400' : ''}
                    ${log.status === 'processing' ? 'bg-blue-500/20 text-blue-400' : ''}
                    ${log.status === 'error' ? 'bg-red-500/20 text-red-400' : ''}
                    ${log.status === 'pending' ? 'bg-white/5 text-white/40' : ''}
                  `}>
                    {log.status.toUpperCase()}
                  </span>
                  <span className="text-white/80 font-medium">
                    {log.label[langKey]}
                  </span>
                </div>
                {log.detail && (
                  <p className="text-white/30 mt-1.5 text-xs italic">
                    ↳ {log.detail}
                  </p>
                )}
              </div>
            </div>
          ))}
          <div ref={logsEndRef} className="flex items-center gap-2 text-sage-500 pt-2 ml-2">
            <span className="w-2 h-4 bg-sage-500/80 animate-pulse"></span>
            <span className="text-[10px] uppercase tracking-wider animate-pulse">Executing Protocol...</span>
          </div>
        </div>
        <style>{`
          @keyframes logEntry {
            from { opacity: 0; transform: translateY(5px); }
            to { opacity: 1; transform: translateY(0); }
          }
          .animate-log-entry { animation: logEntry 0.2s ease-out forwards; }
        `}</style>
      </div>
    );
  }

  if (!content) return null;

  return (
    <>
      <div className="bg-paper shadow-2xl rounded-xl overflow-hidden border border-stone-200 animate-fade-in max-w-4xl mx-auto">
        <div className="bg-sage-50/80 backdrop-blur-sm px-6 py-4 border-b border-sage-200 flex justify-between items-center no-print">
          <div className="flex gap-2">
            <div className="w-2.5 h-2.5 rounded-full bg-stone-300"></div>
            <div className="w-2.5 h-2.5 rounded-full bg-stone-300"></div>
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowChatSession(true)} className="bg-sage-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-sage-700 transition-all shadow-md">
               💬 {language === Language.English ? "Discuss with AI" : "與 AI 探討"}
            </button>
            <button onClick={handleCopy} className="bg-white border border-stone-200 px-4 py-2 rounded-lg text-sm font-bold text-stone-600 hover:bg-stone-50 transition-all">
               {language === Language.English ? "Copy" : "複製"}
            </button>
            <button onClick={handleDownloadWord} className="bg-white border border-stone-200 px-4 py-2 rounded-lg text-sm font-bold text-stone-600 hover:bg-stone-50 transition-all">
               {language === Language.English ? "Export" : "匯出"}
            </button>
          </div>
        </div>

        <div className="p-12 md:p-20">
          <div ref={contentRef} className="prose prose-stone prose-lg md:prose-xl max-w-none font-serif leading-relaxed">
            <Markdown
              components={{
                h1: (p) => <h1 className="text-5xl font-bold text-sage-800 border-b border-gold-500/30 pb-6 mb-12 tracking-tight" {...p} />,
                h2: (p) => <h2 className="text-3xl font-bold text-sage-700 mt-16 mb-8 flex items-center gap-4 before:w-1 before:h-8 before:bg-gold-500" {...p} />,
                blockquote: (p) => <blockquote className="border-l-4 border-sage-600 bg-sage-50 py-6 px-8 italic text-stone-600 rounded-r-xl my-10" {...p} />,
                p: (p) => <p className="mb-6 text-stone-800 text-justify" {...p} />
              }}
            >
              {content}
            </Markdown>
          </div>
        </div>
      </div>
      {showChatSession && <ChatSession contextContent={content} language={language} onClose={() => setShowChatSession(false)} apiKey={apiKey} />}
    </>
  );
};

import React, { useState } from 'react';
import { GoogleGenAI } from "@google/genai";

interface ApiKeyInputProps {
  onValidKey: (key: string) => void;
}

export const ApiKeyInput: React.FC<ApiKeyInputProps> = ({ onValidKey }) => {
  const [keyInput, setKeyInput] = useState('');
  const [isValidating, setIsValidating] = useState(false);
  const [error, setError] = useState('');

  const handleValidate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!keyInput.trim()) return;
    setIsValidating(true);
    setError('');

    try {
      const ai = new GoogleGenAI({ apiKey: keyInput.trim() });
      await ai.models.countTokens({
        model: 'gemini-3-flash-preview',
        contents: 'ping',
      });
      onValidKey(keyInput.trim());
    } catch (err: any) {
      setError('Connection Failed. Please verify your API Key and network status.');
    } finally {
      setIsValidating(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#F7F5F0] flex flex-col items-center justify-center p-6 font-sans">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl border border-stone-200 overflow-hidden animate-fade-in">
        <div className="bg-sage-600 p-10 text-center">
          <div className="w-20 h-20 bg-white/10 rounded-2xl flex items-center justify-center mx-auto mb-6 backdrop-blur-md border border-white/20">
            <span className="font-serif text-white font-bold text-4xl">S</span>
          </div>
          <h1 className="font-serif text-3xl font-bold text-white mb-2">Sacred Studies AI</h1>
          <p className="text-sage-100 text-[10px] uppercase tracking-[0.3em] font-bold">Encrypted Local Session</p>
        </div>

        <div className="p-10">
          <p className="text-stone-500 mb-8 text-sm leading-relaxed text-center">
            This platform requires a <strong>Google Gemini API Key</strong> to operate. 
            Your key is handled with atomic integrity and is never stored externally.
          </p>

          <form onSubmit={handleValidate} className="space-y-6">
            <div className="space-y-2">
              <label className="block text-[10px] font-bold text-sage-600 uppercase tracking-widest">
                API Protocol Key
              </label>
              <input
                type="password"
                value={keyInput}
                onChange={(e) => setKeyInput(e.target.value)}
                placeholder="AIza..."
                className="w-full p-4 bg-stone-50 border border-stone-200 rounded-xl focus:ring-2 focus:ring-sage-500 outline-none transition-all font-mono text-sm"
              />
            </div>

            {error && <div className="p-4 bg-red-50 border border-red-100 rounded-xl text-red-600 text-xs font-bold">{error}</div>}

            <button
              type="submit"
              disabled={!keyInput || isValidating}
              className={`w-full py-4 rounded-xl font-bold text-white shadow-xl transition-all transform active:scale-[0.98] ${
                !keyInput || isValidating ? 'bg-stone-300' : 'bg-gradient-to-r from-sage-600 to-sage-800'
              }`}
            >
              {isValidating ? "Synchronizing..." : "Initiate System"}
            </button>
          </form>

          <div className="mt-8 text-center">
             <a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noopener noreferrer" className="text-xs text-stone-400 hover:text-sage-600 transition-colors uppercase tracking-widest font-bold">
               Obtain Protocol Key
             </a>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { StepWizard } from './components/StepWizard';
import { ConfigurationForm } from './components/ConfigurationForm';
import { SelectorGrid } from './components/SelectorGrid';
import { ResultDisplay } from './components/ResultDisplay';
import { ApiKeyInput } from './components/ApiKeyInput';
import { StudyConfig, KnowledgeLevel, StudyType, Language, ActivityLog } from './types';
import { APPROACHES, TRADITIONS, UI_TEXT, KNOWLEDGE_LEVEL_LABELS, STUDY_TYPE_LABELS } from './constants';
import { generateStudyGuide } from './services/geminiService';

const App: React.FC = () => {
  // Strict non-retention policy: apiKey starts as null and is never persisted.
  const [userApiKey, setUserApiKey] = useState<string | null>(null);
  const [step, setStep] = useState(1);
  const [language, setLanguage] = useState<Language>(Language.English);

  const [config, setConfig] = useState<StudyConfig>({
    passage: '',
    topic: '',
    knowledgeLevel: KnowledgeLevel.Intermediate,
    studyType: StudyType.Comprehensive,
    duration: 60,
    approaches: [],
    customApproach: '',
    traditions: [],
    language: Language.English
  });

  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [isDirty, setIsDirty] = useState(true);

  useEffect(() => {
    setConfig(prev => ({ ...prev, language }));
  }, [language]);

  const handleConfigChange = (updates: Partial<StudyConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
    setIsDirty(true);
  };

  const handleNext = async () => {
    if (step < 4) {
      setStep(step + 1);
    } else {
      if (!userApiKey) return;
      setIsGenerating(true);
      setLogs([]);
      try {
        const content = await generateStudyGuide(config, userApiKey, (log) => {
          setLogs(prev => [...prev, log]);
        });
        setGeneratedContent(content);
        setIsDirty(false);
      } catch (error) {
        console.error(error);
        setGeneratedContent("Operational Fault: Generation pipeline interrupted. Please verify credentials.");
      } finally {
        setIsGenerating(false);
      }
    }
  };

