                      <dd className="font-serif text-2xl font-bold text-charcoal">{config.topic || "-"}</dd>
                    </div>
                  </dl>
                </div>
                <ResultDisplay content={generatedContent} isGenerating={isGenerating} language={language} logs={logs} apiKey={userApiKey} />
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-stone-200 sticky bottom-0 z-40 py-8 no-print shadow-[0_-10px_40px_rgba(0,0,0,0.03)]">
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          <button onClick={() => step > 1 && setStep(step - 1)} disabled={step === 1 || isGenerating} className="px-8 py-4 rounded-xl font-bold text-stone-400 hover:text-sage-700 transition-all disabled:opacity-0">
            {t.back[langKey]}
          </button>
          <button
            onClick={handleNext}
            disabled={!config.passage || isGenerating || (!isDirty && generatedContent !== '')}
            className={`px-12 py-4 rounded-2xl font-bold text-lg text-white shadow-2xl transition-all transform hover:-translate-y-1 active:translate-y-0 flex items-center gap-3 ${
              !config.passage || isGenerating || (!isDirty && generatedContent !== '')
                ? 'bg-stone-300 shadow-none'
                : 'bg-sage-600 hover:bg-sage-700 shadow-sage-600/30'
            }`}
          >
            {isGenerating ? "Synthesizing..." : step < 4 ? t.next[langKey] : t.generate[langKey]}
          </button>
        </div>
      </footer>
    </div>
  );
};

