import { GoogleGenAI } from "@google/genai";
import { StudyConfig, Language, StudyType, KnowledgeLevel, ActivityLog } from "../types";

// Using gemini-3-flash-preview for high performance and increased rate limits
const MODEL_NAME = "gemini-3-flash-preview";

const getToneAndStyle = (type: StudyType, level: KnowledgeLevel, isChinese: boolean) => {
  let tone = "";
  switch (type) {
    case StudyType.Sermon:
      tone = "ROLE: Expert Homiletician. TONE: Passionate, oral-focused, persuasive. Use 'we' language.";
      break;
    case StudyType.Devotional:
      tone = "ROLE: Spiritual Director. TONE: Warm, contemplative, soul-stirring.";
      break;
    case StudyType.Academic:
    case StudyType.Comprehensive:
      tone = "ROLE: Biblical Scholar. TONE: Rigorous, objective, technical. Engage original languages.";
      break;
    case StudyType.Discussion:
      tone = "ROLE: Facilitator. TONE: Engaging, inquiry-based, dialogical.";
      break;
  }
  if (level === KnowledgeLevel.Scholarly) tone += " DEPTH: Maximum. Analyze linguistic nuances.";
  else if (level === KnowledgeLevel.Beginner) tone += " DEPTH: Introductory. Use clear analogies.";
  return tone;
};

export const generateTopic = async (passage: string, language: Language): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const isChinese = language === Language.TraditionalChinese;

  const prompt = `
    Analyze the biblical passage: "${passage}".
    Generate 3 distinct, contemporary, and engaging theological themes or titles.
    Language: ${isChinese ? 'Traditional Chinese (繁體中文)' : 'English'}
    Format: JSON array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: { temperature: 0.9, responseMimeType: "application/json" }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Topic generation fault:", error);
    return [];
  }
};

export const generateStudyGuide = async (
  config: StudyConfig, 
  onLog: (log: ActivityLog) => void
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const isChinese = config.language === Language.TraditionalChinese;
  const toneInstruction = getToneAndStyle(config.studyType, config.knowledgeLevel, isChinese);

  const log = (en: string, zh: string, status: 'pending' | 'processing' | 'success' | 'error' = 'processing', detail?: string) => {
    onLog({ id: crypto.randomUUID(), timestamp: new Date(), label: { en, zh }, status, detail });
  };

  const approachesString = config.approaches.map(id => id === 'custom' ? `Custom: ${config.customApproach}` : id).join(', ');

  const systemInstruction = `
    You are an elite Biblical Scholar. Target: "${config.passage}" | Topic: "${config.topic}"
    Context: ${config.studyType} | Level: ${config.knowledgeLevel} | Language: ${isChinese ? 'Traditional Chinese' : 'English'}
    ${toneInstruction}
  `;

  try {
    log("Initializing Neural Engine", "正在初始化引擎", 'processing', `Model: ${MODEL_NAME}`);
    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: { systemInstruction, temperature: 0.7 }
    });

    const sections = [
      { id: "intro", label: { en: "Contextual Framework", zh: "背景與架構分析" }, prompt: "Generate Section 1: Introduction and Context." },
      { id: "exegesis", label: { en: "Exegetical Deep-Dive", zh: "深層釋經" }, prompt: `Detailed Exegesis using ${approachesString}.` },
      { id: "tradition", label: { en: "Historical Synthesis", zh: "歷史與神學綜合" }, prompt: `Synthesis with ${config.traditions.join(', ')} traditions.` },
      { id: "application", label: { en: "Existential Application", zh: "實踐應用" }, prompt: "Conclusion and practical implications." }
    ];

    let fullContent = "";
    for (const section of sections) {
      log(`Constructing ${section.label.en}`, `正在構建 ${section.label.zh}`, 'processing');
      const result = await chat.sendMessage({ message: section.prompt });
      fullContent += "\n\n" + (result.text || "");
      log(`${section.label.en} Finalized`, `${section.label.zh} 已完成`, 'success');
    }

    return fullContent.trim();
  } catch (error: any) {
    const errorMsg = error?.message || "Unknown Protocol Error";
    log("System Fault", "偵測到系統故障", 'error', errorMsg);
    throw error;
  }
};

