    studyType: StudyType.Comprehensive,
    duration: 60,
    approaches: [],
    customApproach: '',
    traditions: [],
    language: Language.English
  });

  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [isDirty, setIsDirty] = useState(true);

  useEffect(() => {
    setConfig(prev => ({ ...prev, language }));
  }, [language]);

  const handleConfigChange = (updates: Partial<StudyConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
    setIsDirty(true);
  };

  const handleNext = async () => {
    if (step < 4) {
      setStep(step + 1);
    } else {
      setIsGenerating(true);
      setLogs([]);
      try {
        const content = await generateStudyGuide(config, (log) => {
          setLogs(prev => [...prev, log]);
        });
        setGeneratedContent(content);
        setIsDirty(false);
      } catch (error: any) {
        console.error("Generation Error:", error);

        const errorMsg = error?.message || "";
        if (errorMsg.includes("Requested entity was not found") || errorMsg.includes("API_KEY_INVALID")) {
          await window.aistudio.openSelectKey();
        } else if (errorMsg.includes("429") || errorMsg.includes("Resource has been exhausted")) {
          setGeneratedContent("Quota Exhausted: Your API Key has reached its rate limit. Please wait a minute or switch to a paid project key in the activation settings.");
        } else {
          setGeneratedContent(`Operational Fault: ${errorMsg || "Generation pipeline interrupted."}`);
        }
      } finally {
        setIsGenerating(false);
      }
    }
