                language={language}
                customInputId="custom"
                customInputValue={config.customApproach}
                onCustomInputChange={(val) => handleConfigChange({ customApproach: val })}
              />
            )}
            {step === 3 && (
              <SelectorGrid
                title={t.selectTraditionsTitle[langKey]}
                subtitle={t.selectTraditionsSub[langKey]}
                items={TRADITIONS}
                selectedIds={config.traditions}
                onToggle={(id) => handleConfigChange({ traditions: config.traditions.includes(id) ? config.traditions.filter(t => t !== id) : [...config.traditions, id] })}
                language={language}
              />
            )}
            {step === 4 && (
              <div className="space-y-12">
                <div className="bg-white p-10 rounded-3xl border border-stone-200 shadow-xl max-w-4xl mx-auto no-print">
                  <h2 className="font-serif text-3xl font-bold text-sage-800 mb-8 text-center border-b border-stone-100 pb-6">{t.reviewConfig[langKey]}</h2>

                  <div className="space-y-8">
                    {/* Primary Context */}
                    <dl className="grid grid-cols-1 md:grid-cols-2 gap-8 text-base">
                      <div className="bg-stone-50 p-6 rounded-2xl">
                        <dt className="text-[10px] font-bold text-sage-600 uppercase tracking-widest mb-2">{t.passageLabel[langKey]}</dt>
                        <dd className="font-serif text-2xl font-bold text-charcoal">{config.passage || "-"}</dd>
                      </div>
                      <div className="bg-stone-50 p-6 rounded-2xl">
                        <dt className="text-[10px] font-bold text-sage-600 uppercase tracking-widest mb-2">{t.topicLabel[langKey]}</dt>
                        <dd className="font-serif text-2xl font-bold text-charcoal">{config.topic || "-"}</dd>
                      </div>
                    </dl>

                    {/* Meta Parameters */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="border border-stone-100 p-5 rounded-xl">
                        <dt className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-1">{t.knowledgeLabel[langKey]}</dt>
