import { GoogleGenAI } from "@google/genai";
import { StudyConfig, Language, StudyType, KnowledgeLevel, ActivityLog } from "../types";

// Using gemini-3-flash-preview for high performance and increased rate limits
const MODEL_NAME = "gemini-3-flash-preview";

const getToneAndStyle = (type: StudyType, level: KnowledgeLevel, isChinese: boolean) => {
  let tone = "";
  switch (type) {
    case StudyType.Sermon:
      tone = "ROLE: Expert Homiletician. TONE: Passionate, oral-focused, persuasive. Use 'we' language.";
      break;
    case StudyType.Devotional:
      tone = "ROLE: Spiritual Director. TONE: Warm, contemplative, soul-stirring.";
      break;
    case StudyType.Academic:
    case StudyType.Comprehensive:
      tone = "ROLE: Biblical Scholar. TONE: Rigorous, objective, technical. Engage original languages.";
      break;
    case StudyType.Discussion:
      tone = "ROLE: Facilitator. TONE: Engaging, inquiry-based, dialogical.";
      break;
  }
  if (level === KnowledgeLevel.Scholarly) tone += " DEPTH: Maximum. Analyze linguistic nuances and critical apparatus.";
  else if (level === KnowledgeLevel.Beginner) tone += " DEPTH: Introductory. Use clear analogies.";
  return tone;
};

export const generateTopic = async (passage: string, language: Language): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const isChinese = language === Language.TraditionalChinese;

  const prompt = `
    Analyze the biblical passage: "${passage}".
    Generate 3 distinct, contemporary, and engaging theological themes or titles.
    Language: ${isChinese ? 'Traditional Chinese (繁體中文)' : 'English'}
    Format: JSON array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: { temperature: 0.9, responseMimeType: "application/json" }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Topic generation fault:", error);
    return [];
  }
};

export const generateStudyGuide = async (
  config: StudyConfig, 
