  let tone = "";
  switch (type) {
    case StudyType.Sermon:
      tone = "ROLE: Master Homiletician and Preacher. STYLE: Rhetorically powerful, pastoral, and illustrative. Structure the output with clear 'points' that are memorable and move the listener to action. Use high-quality prose suitable for spoken delivery.";
      break;
    case StudyType.Devotional:
      tone = "ROLE: Wise Spiritual Guide. STYLE: Reflective, soul-stirring, and accessible. Focus on internal heart transformation and contemplative inquiry. Use beautiful, literary prose that invites quiet meditation.";
      break;
    case StudyType.Academic:
      tone = "ROLE: Distinguished Biblical Scholar. STYLE: Peer-review quality research. Rigorous, dense with evidence, objective, and analytically sharp. Use formal academic vocabulary and address critical debates in the field.";
      break;
    case StudyType.Comprehensive:
      tone = "ROLE: Senior Theological Analyst. STYLE: All-encompassing, systematic, and structured. Bridge the gap between academic rigor and practical clarity. Use professional, clear, and comprehensive language.";
      break;
    case StudyType.Discussion:
      tone = "ROLE: Insightful Socratic Facilitator. STYLE: Inquiry-based, balanced, and engaging. Focus on questions that probe beneath the surface. Provide 'Leaders Notes' to guide the flow of conversation.";
      break;
  }

  if (level === KnowledgeLevel.Scholarly) tone += " DEPTH: Exhaustive. Engage with the Greek/Hebrew text, variant readings, and historical-grammatical complexities.";
  else if (level === KnowledgeLevel.Advanced) tone += " DEPTH: Substantial. Assume high literacy and explore advanced themes.";
  else if (level === KnowledgeLevel.Beginner) tone += " DEPTH: Foundational. Explain complex terms simply without losing depth.";

  return tone;
};

