export const generateStudyGuide = async (
  config: StudyConfig, 
  onLog: (log: ActivityLog) => void
): Promise<StudyGuideResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const isChinese = config.language === Language.TraditionalChinese;
  const toneInstruction = getToneAndStyle(config.studyType, config.knowledgeLevel, isChinese);

  const log = (en: string, zh: string, status: 'pending' | 'processing' | 'success' | 'error' = 'processing', detail?: string) => {
    onLog({ id: crypto.randomUUID(), timestamp: new Date(), label: { en, zh }, status, detail });
  };

  const approachesString = config.autoResearch 
    ? "the latest contemporary academic exegesis and peer-reviewed scholarly consensus" 
    : config.approaches.map(id => id === 'custom' ? `Custom: ${config.customApproach}` : id).join(', ');

  const traditionsString = config.autoResearch
    ? "the most influential historical and modern theological traditions applicable to this text"
    : config.traditions.join(', ');

  const systemInstruction = `
    You are an elite Biblical Scholar and Professional Content Designer.
    Target: "${config.passage}" | Topic: "${config.topic}"
    Context: ${config.studyType} | Level: ${config.knowledgeLevel} | Language: ${isChinese ? 'Traditional Chinese' : 'English'}

    ${toneInstruction}

    CRITICAL FORMATTING RULES:
    1. Do NOT wrap Greek, Hebrew, or any non-English text in dollar signs ($). This is not a math document.
    2. Use standard Markdown for structure: # and ## for headers. 
    3. Use **Bold** for original scripts (Unicode), *Italics* for transliterations.
    4. Provide the BEST QUALITY writing for the selected genre. This should be indistinguishable from professional published material.

    IMPORTANT PROTOCOL: 
    When performing exegesis, do NOT provide a general summary. 
    You MUST provide a granular analysis. Break down "${config.passage}" into units. 
    Include original language word studies for each unit (Plain Unicode text).
  `;

  try {
    log("Initializing Research Engine", "正在初始化研究引擎", 'processing', `Model: ${MODEL_NAME}`);

    const configParams: any = {
      systemInstruction,
      temperature: 0.7,
    };

    if (config.autoResearch) {
      configParams.tools = [{ googleSearch: {} }];
      log("Deploying Web Grounding", "正在部署全球學術網絡檢索", 'processing', "Scanning current scholarly monographs and journals...");
    }

    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: configParams
    });

    const sections = [
      { 
        id: "intro", 
        label: { en: "Contextual Framework", zh: "背景與架構分析" }, 
        prompt: `Generate Section 1: Introduction, Literary Context, and Socio-Historical Setting. If auto-researching, find the latest critical consensus on the date, authorship, and setting of ${config.passage}.` 
      },
      { 
        id: "exegesis", 
        label: { en: "Exegetical Deep-Dive", zh: "深層釋經" }, 
        prompt: `
          Generate Section 2: Detailed Exegesis using ${approachesString}.
          MANDATORY: Perform a granular, verse-by-verse analysis of ${config.passage}.
          For each unit:
          1. Original Language Insight: Significant Greek/Hebrew word studies.
          2. Analytical Discussion: How this unit functions within the whole.
        ` 
      },
      { 
        id: "tradition", 
        label: { en: "Synthesis & History", zh: "歷史與神學綜合" }, 
        prompt: `Generate Section 3: Synthesis with ${traditionsString}. Explore the reception history and theological impact.` 
      },
      { 
        id: "application", 
        label: { en: "Existential Application", zh: "實踐應用" }, 
        prompt: "Generate Section 4: Practical implications and final conclusion based on the study." 
      }
    ];

    let fullContent = "";
    let allSources: { uri: string; title: string }[] = [];

    for (const section of sections) {
      log(`Synthesizing ${section.label.en}`, `正在合成 ${section.label.zh}`, 'processing');
      const result = await chat.sendMessage({ message: section.prompt });
      fullContent += "\n\n" + (result.text || "");

      // Extract grounding sources if they exist
      const chunks = result.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (chunks) {
        chunks.forEach((chunk: any) => {
          if (chunk.web) {
            allSources.push({ uri: chunk.web.uri, title: chunk.web.title });
          }
        });
      }

      log(`${section.label.en} Finalized`, `${section.label.zh} 已完成`, 'success');
    }

    // De-duplicate sources
    const uniqueSources = Array.from(new Set(allSources.map(s => s.uri)))
      .map(uri => allSources.find(s => s.uri === uri)!);

    return { text: fullContent.trim(), sources: uniqueSources };
  } catch (error: any) {
    const errorMsg = error?.message || "Unknown Protocol Error";
    log("System Fault", "偵測到系統故障", 'error', errorMsg);
    throw error;
  }
};

