    setTopicSuggestions([]);

    try {
      const topics = await generateTopic(config.passage, language);
      if (Array.isArray(topics) && topics.length > 0) {
        setTopicSuggestions(topics);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsGeneratingTopic(false);
    }
  };

  const handleSelectTopic = (selectedTopic: string) => {
    onChange({ topic: selectedTopic });
    setTopicSuggestions([]);
  };

  return (
    <div className="space-y-10 animate-fade-in max-w-4xl mx-auto">
      {/* Passage Input */}
      <div className="space-y-3">
        <label className="block text-xl font-serif font-bold text-sage-800">
          {t.passageLabel[langKey]}
        </label>
        <input
          type="text"
          value={config.passage}
          onChange={(e) => onChange({ passage: e.target.value })}
          placeholder={t.passagePlaceholder[langKey]}
          className="w-full p-6 text-xl md:text-2xl bg-white border-2 border-stone rounded-xl focus:ring-4 focus:ring-sage-100 focus:border-sage-600 outline-none transition-all shadow-sm font-serif text-charcoal placeholder-gray-300"
        />
      </div>

      {/* Auto-Research Toggle */}
      <div 
        onClick={() => onChange({ autoResearch: !config.autoResearch })}
        className={`p-6 rounded-2xl border-2 transition-all cursor-pointer flex items-center gap-6 group ${
          config.autoResearch 
          ? 'bg-sage-50 border-sage-600 shadow-md' 
          : 'bg-white border-stone-200 hover:border-sage-300'
        }`}
      >
        <div className={`w-14 h-8 rounded-full relative transition-all ${config.autoResearch ? 'bg-sage-600' : 'bg-stone-300'}`}>
          <div className={`absolute top-1 w-6 h-6 bg-white rounded-full transition-all shadow-sm ${config.autoResearch ? 'left-7' : 'left-1'}`}></div>
        </div>
        <div className="flex-1">
          <h4 className={`font-bold transition-all ${config.autoResearch ? 'text-sage-800' : 'text-stone-500'}`}>
            {t.autoResearchLabel[langKey]}
          </h4>
          <p className="text-xs text-stone-400 mt-0.5">{t.autoResearchDesc[langKey]}</p>
        </div>
        <div className={`text-2xl transition-all ${config.autoResearch ? 'grayscale-0 scale-110' : 'grayscale'}`}>🔍</div>
      </div>

      {/* Topic Input with Auto-Generate */}
      <div className="space-y-3">
        <div className="flex justify-between items-end">
          <label className="block text-xl font-serif font-bold text-sage-800">
            {t.topicLabel[langKey]}
          </label>
          <button
            onClick={handleAutoGenerateTopic}
            disabled={!config.passage || isGeneratingTopic}
            className={`text-sm font-bold uppercase tracking-wider flex items-center gap-2 px-4 py-2 rounded-lg transition-all
              ${!config.passage 
                ? 'text-gray-300 cursor-not-allowed' 
                : 'text-gold-600 hover:bg-gold-50 hover:text-gold-700'
              }`}
          >
            {isGeneratingTopic ? (
              <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
            ) : (
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            )}
            {t.generateIdeas[langKey]}
          </button>
        </div>
        <input
          type="text"
          value={config.topic}
          onChange={(e) => onChange({ topic: e.target.value })}
          placeholder={t.topicPlaceholder[langKey]}
          className="w-full p-6 text-xl bg-white border-2 border-stone rounded-xl focus:ring-4 focus:ring-sage-100 focus:border-sage-600 outline-none transition-all shadow-sm font-serif text-charcoal placeholder-gray-300"
        />

        {/* Topic Suggestions Grid */}
        {topicSuggestions.length > 0 && (
          <div className="grid gap-3 pt-2 animate-fade-in">
            <p className="text-xs font-bold text-sage-500 uppercase tracking-wider">
              {t.selectTheme[langKey]}
            </p>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {topicSuggestions.map((suggestion, idx) => (
                <button
                  key={idx}
                  onClick={() => handleSelectTopic(suggestion)}
                  className="text-left p-4 rounded-lg border border-sage-200 bg-white hover:bg-sage-50 hover:border-sage-400 hover:shadow-md transition-all group"
                >
                  <span className="font-serif text-lg font-bold text-sage-800 group-hover:text-sage-900 block leading-tight">
                    {suggestion}
                  </span>
                </button>
              ))}
            </div>
          </div>
        )}
      </div>

      {/* Selectors Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="space-y-3">
          <label className="block text-lg font-bold text-charcoal/80">
            {t.knowledgeLabel[langKey]}
          </label>
          <div className="relative">
            <select
              value={config.knowledgeLevel}
              onChange={(e) => onChange({ knowledgeLevel: e.target.value as KnowledgeLevel })}
              className="w-full p-4 text-lg bg-white border-2 border-stone rounded-xl focus:ring-2 focus:ring-sage-600 outline-none appearance-none text-charcoal"
            >
              {Object.values(KnowledgeLevel).map((level) => (
                <option key={level} value={level}>
                  {KNOWLEDGE_LEVEL_LABELS[level][langKey]}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className="space-y-3">
          <label className="block text-lg font-bold text-charcoal/80">
            {t.typeLabel[langKey]}
          </label>
          <div className="relative">
            <select
              value={config.studyType}
              onChange={(e) => onChange({ studyType: e.target.value as StudyType })}
              className="w-full p-4 text-lg bg-white border-2 border-stone rounded-xl focus:ring-2 focus:ring-sage-600 outline-none appearance-none text-charcoal"
            >
              {Object.values(StudyType).map((type) => (
                <option key={type} value={type}>
                  {STUDY_TYPE_LABELS[type][langKey]}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className="space-y-3">
          <label className="block text-lg font-bold text-charcoal/80">
            {t.durationLabel[langKey]}: <span className="text-sage-700 font-serif text-xl">{config.duration} {t.minutes[langKey]}</span>
          </label>
          <div className="pt-2">
            <input
              type="range"
              min="15"
              max="180"
              step="15"
              value={config.duration}
              onChange={(e) => onChange({ duration: parseInt(e.target.value) })}
              className="w-full h-3 bg-stone rounded-lg appearance-none cursor-pointer accent-sage-600 hover:accent-sage-700"
            />
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import Markdown from 'react-markdown';
import { Language, ActivityLog } from '../types';
import { UI_TEXT } from '../constants';
import { ChatSession } from './ChatSession';

interface ResultDisplayProps {
  content: string;
  isGenerating: boolean;
  language: Language;
  logs: ActivityLog[];
  sources?: { uri: string; title: string }[];
}

export const ResultDisplay: React.FC<ResultDisplayProps> = ({ content, isGenerating, language, logs, sources }) => {
  const [showChatSession, setShowChatSession] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const langKey = language === Language.English ? 'en' : 'zh';
  const t = UI_TEXT;

  useEffect(() => {
    if (isGenerating && logsEndRef.current) {
      logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, isGenerating]);

  const handleCopy = async () => {
    await navigator.clipboard.writeText(content);
    alert(language === Language.English ? "Captured to clipboard." : "內容已存入剪貼簿。");
  };

  const handleDownloadWord = () => {
    if (!contentRef.current) return;
    const html = `<html><head><meta charset='utf-8'><style>body{font-family:'Times New Roman',serif;padding:20px;}h1{color:#4A5D23;}h2{color:#4A5D23;border-bottom:1px solid #ddd;}</style></head><body>${contentRef.current.innerHTML}</body></html>`;
    const blob = new Blob(['\ufeff', html], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `SacredStudy_${new Date().toISOString().slice(0,10)}.doc`;
    link.click();
  };

  if (isGenerating) {
    return (
      <div className="bg-[#1a1a1a] rounded-xl border border-white/10 shadow-2xl overflow-hidden font-mono text-[13px] max-w-3xl mx-auto my-12 animate-fade-in ring-1 ring-white/5">
        <div className="bg-white/5 p-4 border-b border-white/10 flex justify-between items-center">
          <div className="flex space-x-2">
            <div className="w-2.5 h-2.5 rounded-full bg-red-500/40"></div>
            <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/40"></div>
            <div className="w-2.5 h-2.5 rounded-full bg-green-500/40"></div>
          </div>
          <div className="text-white/40 text-[10px] uppercase tracking-[0.2em] font-bold">
            Live Synthesis Terminal
          </div>
        </div>
        <div className="p-8 h-[450px] overflow-y-auto space-y-4 scrollbar-thin scrollbar-thumb-white/10 scrollbar-track-transparent">
          {logs.map((log) => (
            <div key={log.id} className="flex gap-4 animate-log-entry border-l border-white/5 pl-4 ml-2">
              <span className="text-white/20 shrink-0 select-none">
                [{log.timestamp.toLocaleTimeString([], { hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit' })}]
              </span>
              <div className="flex-1">
                <div className="flex items-center gap-3">
                  <span className={`
                    text-[10px] font-bold px-1.5 py-0.5 rounded
                    ${log.status === 'success' ? 'bg-green-500/20 text-green-400' : ''}
                    ${log.status === 'processing' ? 'bg-blue-500/20 text-blue-400' : ''}
                    ${log.status === 'error' ? 'bg-red-500/20 text-red-400' : ''}
                    ${log.status === 'pending' ? 'bg-white/5 text-white/40' : ''}
                  `}>
                    {log.status.toUpperCase()}
                  </span>
                  <span className="text-white/80 font-medium">
                    {log.label[langKey]}
                  </span>
                </div>
                {log.detail && (
                  <p className="text-white/30 mt-1.5 text-xs italic">
                    ↳ {log.detail}
                  </p>
                )}
              </div>
            </div>
          ))}
          <div ref={logsEndRef} className="flex items-center gap-2 text-sage-500 pt-2 ml-2">
            <span className="w-2 h-4 bg-sage-500/80 animate-pulse"></span>
            <span className="text-[10px] uppercase tracking-wider animate-pulse">Executing Protocol...</span>
          </div>
        </div>
      </div>
    );
  }

  if (!content) return null;

  return (
    <>
      <div className="bg-paper shadow-2xl rounded-xl overflow-hidden border border-stone-200 animate-fade-in max-w-4xl mx-auto">
        <div className="bg-sage-50/80 backdrop-blur-sm px-6 py-4 border-b border-sage-200 flex justify-between items-center no-print">
          <div className="flex gap-2">
            <div className="w-2.5 h-2.5 rounded-full bg-stone-300"></div>
            <div className="w-2.5 h-2.5 rounded-full bg-stone-300"></div>
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowChatSession(true)} className="bg-sage-600 text-white px-4 py-2 rounded-lg text-sm font-bold flex items-center gap-2 hover:bg-sage-700 transition-all shadow-md">
               💬 {language === Language.English ? "Consult Assistant" : "與研究助理對話"}
            </button>
            <button onClick={handleDownloadWord} className="bg-white border border-stone-200 px-4 py-2 rounded-lg text-sm font-bold text-stone-600 hover:bg-stone-50 transition-all">
               {language === Language.English ? "Export" : "匯出"}
            </button>
          </div>
        </div>

        <div className="p-12 md:p-20">
          <div ref={contentRef} className="prose prose-stone prose-lg md:prose-xl max-w-none font-serif leading-relaxed">
            <Markdown
              components={{
                h1: (p) => <h1 className="text-5xl font-bold text-sage-800 border-b-2 border-sage-600 pb-8 mb-16 tracking-tight text-center" {...p} />,
                h2: (p) => <h2 className="text-3xl font-bold text-sage-700 mt-20 mb-10 pb-2 border-b border-stone-100 flex items-center gap-4" {...p} />,
                h3: (p) => <h3 className="text-2xl font-bold text-sage-600 mt-12 mb-6" {...p} />,
                blockquote: (p) => <blockquote className="border-l-4 border-gold-500 bg-stone-50/50 py-8 px-10 italic text-stone-700 rounded-r-2xl my-12 shadow-sm font-serif text-2xl" {...p} />,
                p: (p) => <p className="mb-8 text-charcoal text-justify leading-loose" {...p} />,
                ul: (p) => <ul className="list-disc list-outside ml-6 mb-8 space-y-4 text-stone-700" {...p} />,
                ol: (p) => <ol className="list-decimal list-outside ml-6 mb-8 space-y-4 text-stone-700 font-bold" {...p} />,
                li: (p) => <li className="pl-2 font-serif text-lg leading-relaxed text-charcoal font-normal" {...p} />,
                strong: (p) => <strong className="font-bold text-sage-800" {...p} />
              }}
            >
              {content}
            </Markdown>

            {/* Grounding Sources UI */}
            {sources && sources.length > 0 && (
              <div className="mt-20 pt-12 border-t border-stone-200 no-print">
                <h4 className="text-xs font-bold text-sage-600 uppercase tracking-widest mb-6">
                  {t.sources[langKey]}
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {sources.map((source, i) => (
                    <a 
                      key={i} 
                      href={source.uri} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="group p-4 bg-stone-50 border border-stone-200 rounded-xl hover:bg-white hover:border-sage-300 transition-all"
                    >
                      <div className="text-[10px] text-stone-400 font-bold uppercase mb-1">Scholar Link</div>
                      <div className="text-sm font-bold text-sage-800 group-hover:text-sage-600 line-clamp-1">{source.title}</div>
                      <div className="text-[10px] text-stone-300 truncate mt-1">{source.uri}</div>
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
      {showChatSession && <ChatSession contextContent={content} language={language} onClose={() => setShowChatSession(false)} />}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { StepWizard } from './components/StepWizard';
import { ConfigurationForm } from './components/ConfigurationForm';
import { SelectorGrid } from './components/SelectorGrid';
import { ResultDisplay } from './components/ResultDisplay';
import { ApiKeyInput } from './components/ApiKeyInput';
import { StudyConfig, KnowledgeLevel, StudyType, Language, ActivityLog } from './types';
import { APPROACHES, TRADITIONS, UI_TEXT, KNOWLEDGE_LEVEL_LABELS, STUDY_TYPE_LABELS } from './constants';
import { generateStudyGuide } from './services/geminiService';

const App: React.FC = () => {
  const [isActivated, setIsActivated] = useState(false);
  const [step, setStep] = useState(1);
  const [language, setLanguage] = useState<Language>(Language.English);

  const [config, setConfig] = useState<StudyConfig>({
    passage: '',
    topic: '',
    knowledgeLevel: KnowledgeLevel.Intermediate,
    studyType: StudyType.Comprehensive,
    duration: 60,
    approaches: [],
    customApproach: '',
    traditions: [],
    language: Language.English,
    autoResearch: true
  });

  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [sources, setSources] = useState<{ uri: string; title: string }[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [isDirty, setIsDirty] = useState(true);

  useEffect(() => {
    setConfig(prev => ({ ...prev, language }));
  }, [language]);

  const handleConfigChange = (updates: Partial<StudyConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
    setIsDirty(true);
  };

  const handleNext = async () => {
    // If auto-research is on, we skip steps 2 and 3 and go directly to 4 (Review)
    if (config.autoResearch && step === 1) {
      setStep(4);
    } else if (step < 4) {
      setStep(step + 1);
    } else {
      setIsGenerating(true);
      setLogs([]);
      try {
        const result = await generateStudyGuide(config, (log) => {
          setLogs(prev => [...prev, log]);
        });
        setGeneratedContent(result.text);
        setSources(result.sources || []);
        setIsDirty(false);
      } catch (error: any) {
        console.error("Generation Error:", error);
        const errorMsg = error?.message || "";
        if (errorMsg.includes("Requested entity was not found") || errorMsg.includes("API_KEY_INVALID")) {
          await window.aistudio.openSelectKey();
        } else if (errorMsg.includes("429") || errorMsg.includes("Resource has been exhausted")) {
          setGeneratedContent("Quota Exhausted: Your API Key has reached its rate limit.");
        } else {
          setGeneratedContent(`Operational Fault: ${errorMsg || "Generation pipeline interrupted."}`);
        }
      } finally {
        setIsGenerating(false);
      }
    }
  };

  const t = UI_TEXT;
  const langKey = language === Language.English ? 'en' : 'zh';

  if (!isActivated) {
    return <ApiKeyInput onActivated={() => setIsActivated(true)} />;
  }

  const getSelectedLabels = (items: any[], selectedIds: string[]) => {
    if (config.autoResearch) return [t.latestResearch[langKey]];
    return selectedIds.map(id => {
      const item = items.find(i => i.id === id);
      if (id === 'custom' && config.customApproach) return config.customApproach;
      return item ? item.label[langKey] : id;
    }).filter(Boolean);
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-ivory selection:bg-sage-100">
      <Header language={language} onToggleLanguage={() => setLanguage(l => l === Language.English ? Language.TraditionalChinese : Language.English)} />

      <main className="flex-grow">
        <div className="max-w-7xl mx-auto px-6 py-12">
          <div className="no-print">
            <StepWizard currentStep={step} totalSteps={4} onStepClick={setStep} language={language} />
          </div>

          <div className="mt-16">
            {step === 1 && <ConfigurationForm config={config} onChange={handleConfigChange} language={language} />}
            {step === 2 && !config.autoResearch && (
              <SelectorGrid
                title={t.selectApproachesTitle[langKey]}
                subtitle={t.selectApproachesSub[langKey]}
                items={APPROACHES}
                selectedIds={config.approaches}
                onToggle={(id) => handleConfigChange({ approaches: config.approaches.includes(id) ? config.approaches.filter(a => a !== id) : [...config.approaches, id] })}
                language={language}
                customInputId="custom"
                customInputValue={config.customApproach}
                onCustomInputChange={(val) => handleConfigChange({ customApproach: val })}
              />
            )}
            {step === 3 && !config.autoResearch && (
              <SelectorGrid
                title={t.selectTraditionsTitle[langKey]}
                subtitle={t.selectTraditionsSub[langKey]}
                items={TRADITIONS}
                selectedIds={config.traditions}
                onToggle={(id) => handleConfigChange({ traditions: config.traditions.includes(id) ? config.traditions.filter(t => t !== id) : [...config.traditions, id] })}
                language={language}
              />
            )}
            {step === 4 && (
              <div className="space-y-12">
                <div className="bg-white p-10 rounded-3xl border border-stone-200 shadow-xl max-w-4xl mx-auto no-print">
                  <h2 className="font-serif text-3xl font-bold text-sage-800 mb-8 text-center border-b border-stone-100 pb-6">{t.reviewConfig[langKey]}</h2>

                  <div className="space-y-8">
                    <dl className="grid grid-cols-1 md:grid-cols-2 gap-8 text-base">
                      <div className="bg-stone-50 p-6 rounded-2xl">
                        <dt className="text-[10px] font-bold text-sage-600 uppercase tracking-widest mb-2">{t.passageLabel[langKey]}</dt>
                        <dd className="font-serif text-2xl font-bold text-charcoal">{config.passage || "-"}</dd>
                      </div>
                      <div className="bg-stone-50 p-6 rounded-2xl">
                        <dt className="text-[10px] font-bold text-sage-600 uppercase tracking-widest mb-2">{t.topicLabel[langKey]}</dt>
                        <dd className="font-serif text-2xl font-bold text-charcoal">{config.topic || "-"}</dd>
                      </div>
                    </dl>

                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="border border-stone-100 p-5 rounded-xl">
                        <dt className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-1">{t.knowledgeLabel[langKey]}</dt>
                        <dd className="font-bold text-sage-800">{KNOWLEDGE_LEVEL_LABELS[config.knowledgeLevel][langKey]}</dd>
                      </div>
                      <div className="border border-stone-100 p-5 rounded-xl">
                        <dt className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-1">{t.typeLabel[langKey]}</dt>
                        <dd className="font-bold text-sage-800">{STUDY_TYPE_LABELS[config.studyType][langKey]}</dd>
                      </div>
                      <div className="border border-stone-100 p-5 rounded-xl">
                        <dt className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-1">{t.durationLabel[langKey]}</dt>
                        <dd className="font-bold text-sage-800">{config.duration} {t.minutes[langKey]}</dd>
                      </div>
                    </div>

                    <div className="space-y-4">
                      <div className="bg-sage-50/30 p-6 rounded-2xl border border-sage-100">
                        <dt className="text-[10px] font-bold text-sage-600 uppercase tracking-widest mb-3">{t.stepApproaches[langKey]}</dt>
                        <dd className="flex flex-wrap gap-2">
                          {getSelectedLabels(APPROACHES, config.approaches).map((label, i) => (
                            <span key={i} className="px-3 py-1 bg-white border border-sage-200 text-sage-800 rounded-full text-xs font-medium shadow-sm">
                              {label}
                            </span>
                          ))}
                        </dd>
                      </div>

                      <div className="bg-sage-50/30 p-6 rounded-2xl border border-sage-100">
                        <dt className="text-[10px] font-bold text-sage-600 uppercase tracking-widest mb-3">{t.stepTraditions[langKey]}</dt>
                        <dd className="flex flex-wrap gap-2">
                          {config.autoResearch ? (
                            <span className="px-3 py-1 bg-white border border-sage-200 text-sage-800 rounded-full text-xs font-medium shadow-sm">
                              {t.latestResearch[langKey]}
                            </span>
                          ) : getSelectedLabels(TRADITIONS, config.traditions).map((label, i) => (
                            <span key={i} className="px-3 py-1 bg-white border border-sage-200 text-sage-800 rounded-full text-xs font-medium shadow-sm">
                              {label}
                            </span>
                          ))}
                        </dd>
                      </div>
                    </div>
                  </div>
                </div>
                <ResultDisplay content={generatedContent} isGenerating={isGenerating} language={language} logs={logs} sources={sources} />
              </div>
            )}
          </div>
        </div>
      </main>

      <footer className="bg-white border-t border-stone-200 sticky bottom-0 z-40 py-8 no-print shadow-[0_-10px_40px_rgba(0,0,0,0.03)]">
