import { GoogleGenAI } from "@google/genai";
import { StudyConfig, Language, StudyType, KnowledgeLevel, ActivityLog } from "../types";

const MODEL_NAME = "gemini-3-flash-preview";

const getToneAndStyle = (type: StudyType, level: KnowledgeLevel, isChinese: boolean) => {
  let instruction = "";

  switch (type) {
    case StudyType.Sermon:
      instruction = `
        ROLE: Master Homiletician. 
        STYLE: Full Oratory Manuscript. 
        REQUIREMENTS: Use the 'Hook-Book-Look-Took' structure. Avoid bullet points for the main body; write as a preachable narrative. Use evocative, rhythmic prose designed for spoken delivery.
        PROSE: Persuasive, illustrative, and seamless.
      `;
      break;
    case StudyType.Devotional:
      instruction = `
        ROLE: Spiritual Director. 
        STYLE: Literary Meditative Essay. 
        REQUIREMENTS: Focus on heart-transformation and the 'Sensus Plenior'. Use 'Lectio Divina' sensibilities. Write in continuous, reflective paragraphs.
        PROSE: Contemplative, warm, and literary.
      `;
      break;
    case StudyType.Academic:
      instruction = `
        ROLE: Senior Biblical Scholar at a Tier-1 University. 
        STYLE: Rigorous Academic Paper / Journal Article. 
        REQUIREMENTS: MUST avoid point-form or bulleted summaries. Write in dense, sophisticated paragraphs. Address the critical apparatus, source-criticism, and the current 'Status Quaestionis' as an integrated argument. 
        PROSE: Technical, objective, and synthesized. Use formal academic transitions.
      `;
      break;
    case StudyType.Comprehensive:
      instruction = `
        ROLE: Systematic Theological Consultant. 
        STYLE: Encyclopedic Synthesis. 
        REQUIREMENTS: Bridge the gap between the academy and the church. Use a mix of dense technical paragraphs and clear sub-headers.
        PROSE: Balanced, exhaustive, and professional.
      `;
      break;
    case StudyType.Discussion:
      instruction = `
        ROLE: Socratic Pedagogue. 
        STYLE: Inquiry-based Discussion Framework. 
        REQUIREMENTS: Use structured points, numbered questions, and clear headings to facilitate community dialogue. Point-form is acceptable here for clarity.
        PROSE: Engaging, clear, and facilitate-oriented.
      `;
      break;
  }

  const depth = level === KnowledgeLevel.Scholarly ? "EXTREME: Full linguistic and historical-critical analysis. Target: Peer-review quality." : 
                level === KnowledgeLevel.Advanced ? "HIGH: Advanced theological and literary concepts." : 
                "ACCESSIBLE: Foundational truths with professional clarity.";

  return `${instruction}\nDEPTH: ${depth}`;
};

