export const generateTopic = async (passage: string, language: Language): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const isChinese = language === Language.TraditionalChinese;

  const prompt = `
    Biblical Passage: "${passage}"
    Objective: Generate 3 compelling, deep, and contemporary theological themes for a high-end research project.
    Language: ${isChinese ? 'Traditional Chinese' : 'English'}
    Output: JSON array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: { temperature: 0.9, responseMimeType: "application/json" }
    });
    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Topic fault:", error);
    return [];
  }
};

export const generateStudyGuide = async (
  config: StudyConfig, 
  onLog: (log: ActivityLog) => void
): Promise<StudyGuideResponse> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const isChinese = config.language === Language.TraditionalChinese;
  const toneInstruction = getToneAndStyle(config.studyType, config.knowledgeLevel, isChinese);

  const log = (en: string, zh: string, status: 'pending' | 'processing' | 'success' | 'error' = 'processing', detail?: string) => {
    onLog({ id: crypto.randomUUID(), timestamp: new Date(), label: { en, zh }, status, detail });
  };

  const methods = config.autoResearch ? "current scholarly consensus and the latest archaeological/linguistic discoveries" : config.approaches.join(', ');
  const historicalLenses = config.autoResearch ? "the most relevant historical traditions and reception history" : config.traditions.join(', ');

  const systemInstruction = `
    You are an AI-Biblical Scholar for Sacred Studies.
    Passage: "${config.passage}" | Focus: "${config.topic}"
    Target: ${config.studyType} (${config.knowledgeLevel})
    Language: ${isChinese ? 'Traditional Chinese' : 'English'}

    ${toneInstruction}

    FORMATTING:
    - Return clean Markdown. Use # for Title and ## for major sections.
    - NEVER use dollar signs ($) for any text.
    - Use **Bold** for original scripts and *Italics* for transliterations.
    - IMPORTANT: If the genre is Academic, Sermon, or Devotional, avoid bullet points for content synthesis. Use full paragraphs.

    EXEGESIS PROTOCOL:
    - Synthesize findings into a cohesive narrative. 
    - For Academic types, emulate the flow of an Oxford or Cambridge University Press monograph.
    - If Google Search is active, cite specific modern research within the prose.
  `;

  try {
    log("Initializing Research Node", "正在初始化研究節點", 'processing');

    const configParams: any = {
      systemInstruction,
      temperature: 0.6, // Lower temperature for more consistent scholarly prose
    };

    if (config.autoResearch) {
      configParams.tools = [{ googleSearch: {} }];
      log("Deploying Scholar-Net Grounding", "正在部署學術網絡檢索", 'processing', "Scanning global scholarly databases...");
    }

    const chat = ai.chats.create({
      model: MODEL_NAME,
      config: configParams
    });

    const bibPrompt = isChinese 
      ? `生成「參考書目」章節。
         要求：
         1. 嚴格遵循芝加哥格式 (Chicago Manual of Style)。
         2. 包含至少 5-10 個權威學術來源。
         3. 區分主要與次要文獻。
         4. 確保書名為斜體。`
      : `Generate the section: "Selected Bibliography".
         REQUIREMENTS:
         1. Strictly adhere to the Chicago Manual of Style (CMOS) 17th Edition.
         2. Include 5-10 high-quality, verified scholarly sources (Monographs, Peer-reviewed journals).
         3. Use italics for titles.
         4. NO other text after this list.`;

    const sections = [
      { id: "context", label: { en: "Contextual Matrix", zh: "文本與歷史背景" }, prompt: `Write a comprehensive essay section analyzing the socio-historical and literary context of ${config.passage}. Avoid bullet points; synthesize the current scholarship on dating, authorship, and provenance into a cohesive argument.` },
      { id: "exegesis", label: { en: "Exegetical Synthesis", zh: "深層釋經合成" }, prompt: `Synthesize a deep, narrative exegetical analysis of ${config.passage} using ${methods}. Avoid verse-by-verse list formats. Instead, weave linguistic word studies and textual observations into high-level scholarly paragraphs.` },
      { id: "history", label: { en: "Historical Reception", zh: "歷史接受史分析" }, prompt: `Write a narrative section analyzing the interpretation history of ${config.passage} through ${historicalLenses}. Connect historical shifts in interpretation to broader theological developments.` },
      { id: "bibliography", label: { en: "Selected Bibliography", zh: "參考書目合成" }, prompt: bibPrompt }
    ];

    let fullContent = "";
    let allSources: { uri: string; title: string }[] = [];

    for (const section of sections) {
      log(`Synthesizing ${section.label.en}`, `正在合成 ${section.label.zh}`, 'processing');
      const response = await chat.sendMessage({ message: section.prompt });
      fullContent += "\n\n" + (response.text || "");

      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
      if (chunks) {
        chunks.forEach((chunk: any) => {
          if (chunk.web) {
            allSources.push({ uri: chunk.web.uri, title: chunk.web.title });
          }
        });
      }
      log(`${section.label.en} Finalized`, `${section.label.zh} 已完成`, 'success');
    }

    const uniqueSources = Array.from(new Set(allSources.map(s => s.uri)))
      .map(uri => allSources.find(s => s.uri === uri)!)
      .filter(s => s.title && s.uri);

    return { text: fullContent.trim(), sources: uniqueSources };
  } catch (error: any) {
    log("Research Interrupt", "研究中斷", 'error', error?.message);
    throw error;
  }
};

