            <select
              value={config.studyType}
              onChange={(e) => onChange({ studyType: e.target.value as StudyType })}
              className="w-full appearance-none bg-white ring-1 ring-stone-200 rounded-xl px-5 py-4 text-base font-medium text-text-main focus:outline-none focus:ring-2 focus:ring-accent shadow-sm cursor-pointer border-none"
            >
