import React, { useState, useRef, useEffect } from 'react';
import Markdown from 'react-markdown';
import { Language, ActivityLog } from '../types';
import { UI_TEXT } from '../constants';
import { ChatSession } from './ChatSession';

interface ResultDisplayProps {
  content: string;
  isGenerating: boolean;
  language: Language;
  logs: ActivityLog[];
  sources?: { uri: string; title: string }[];
  onSave?: () => void;
  isSaved?: boolean;
}

export const ResultDisplay: React.FC<ResultDisplayProps> = ({ content, isGenerating, language, logs, sources, onSave, isSaved }) => {
  const [showChatSession, setShowChatSession] = useState(false);
  const contentRef = useRef<HTMLDivElement>(null);
  const logsEndRef = useRef<HTMLDivElement>(null);
  const langKey = language === Language.English ? 'en' : 'zh';
  const t = UI_TEXT;

  useEffect(() => {
    if (isGenerating && logsEndRef.current) {
      logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [logs, isGenerating]);

  const handleDownloadWord = () => {
    if (!contentRef.current) return;
    const html = `<html><head><meta charset='utf-8'><style>body{font-family:'Times New Roman',serif;padding:40px;line-height:1.6;}h1{text-align:center;color:#4A5D23;}h2{border-bottom:2px solid #4A5D23;color:#4A5D23;margin-top:40px;}h3{color:#4A5D23;margin-top:30px;}.bib-entry{padding-left:2em;text-indent:-2em;margin-bottom:1em;}p{margin-bottom:1.5em;text-align:justify;}</style></head><body>${contentRef.current.innerHTML}</body></html>`;
    const blob = new Blob(['\ufeff', html], { type: 'application/msword' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `SacredStudy_Manuscript_${new Date().getTime()}.doc`;
    link.click();
  };

  if (isGenerating) {
    return (
      <div className="bg-[#121212] rounded-2xl border border-white/10 shadow-3xl overflow-hidden font-mono text-[13px] max-w-4xl mx-auto my-12 animate-fade-in ring-1 ring-white/5">
        <div className="bg-white/5 p-5 border-b border-white/10 flex justify-between items-center">
          <div className="flex space-x-2">
            <div className="w-3 h-3 rounded-full bg-red-500/40"></div>
            <div className="w-3 h-3 rounded-full bg-yellow-500/40"></div>
            <div className="w-3 h-3 rounded-full bg-green-500/40"></div>
          </div>
          <div className="text-white/40 text-[9px] uppercase tracking-[0.4em] font-bold">
            Scholar Grounding Synthesis
          </div>
        </div>
        <div className="p-10 h-[500px] overflow-y-auto space-y-5 scrollbar-thin scrollbar-thumb-white/10">
          {logs.map((log) => (
            <div key={log.id} className="flex gap-5 animate-log-entry border-l-2 border-white/5 pl-5 ml-2">
              <span className="text-white/20 shrink-0 tabular-nums">
                {log.timestamp.toLocaleTimeString([], { hour12: false, hour: '2-digit', minute:'2-digit', second:'2-digit' })}
              </span>
              <div className="flex-1">
                <div className="flex items-center gap-4">
                  <span className={`
                    text-[9px] font-black px-2 py-0.5 rounded tracking-tighter
                    ${log.status === 'success' ? 'bg-green-500/20 text-green-400' : ''}
                    ${log.status === 'processing' ? 'bg-blue-500/20 text-blue-400' : ''}
                    ${log.status === 'error' ? 'bg-red-500/20 text-red-400' : ''}
                  `}>
                    {log.status.toUpperCase()}
                  </span>
                  <span className="text-white/90 font-medium">
                    {log.label[langKey]}
                  </span>
                </div>
                {log.detail && <p className="text-white/40 mt-2 text-xs font-light leading-relaxed">→ {log.detail}</p>}
              </div>
            </div>
          ))}
          <div ref={logsEndRef} className="flex items-center gap-3 text-sage-500 pt-4 ml-2">
            <span className="w-1.5 h-4 bg-sage-500 animate-pulse"></span>
            <span className="text-[10px] uppercase tracking-[0.2em] font-bold">Structuring Professional Protocol...</span>
          </div>
        </div>
      </div>
    );
  }

  if (!content) return null;

  const isBibliographySection = (text: string) => {
    const lower = text.toLowerCase();
    return lower.includes("bibliography") || lower.includes("參考書目");
  };

  return (
    <>
      <div className="bg-paper shadow-3xl rounded-2xl overflow-hidden border border-stone-200 animate-fade-in max-w-5xl mx-auto ring-1 ring-black/5">
        <div className="bg-white/90 backdrop-blur-xl px-8 py-5 border-b border-stone-100 flex justify-between items-center no-print sticky top-20 z-30">
          <div className="flex items-center gap-4">
             <div className="flex gap-1.5">
               <div className="w-2 h-2 rounded-full bg-sage-500"></div>
               <div className="w-2 h-2 rounded-full bg-sage-200"></div>
             </div>
             <span className="text-[10px] uppercase tracking-[0.3em] font-black text-stone-400 border-l border-stone-200 pl-4">Biblical Manuscript Research</span>
          </div>
          <div className="flex gap-3">
            {onSave && (
              <button 
                onClick={onSave} 
                disabled={isSaved}
                className={`px-5 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2.5 transition-all shadow-lg active:scale-95 ${
                  isSaved 
                    ? 'bg-green-500 text-white shadow-green-600/20' 
                    : 'bg-accent text-white shadow-accent/20 hover:bg-gold-600'
                }`}
              >
                 <span className="material-symbols-outlined text-lg">{isSaved ? 'check_circle' : 'library_add'}</span>
                 {isSaved ? t.saved[langKey] : t.saveToLibrary[langKey]}
              </button>
            )}
            <button onClick={() => setShowChatSession(true)} className="bg-sage-600 text-white px-5 py-2.5 rounded-xl text-sm font-bold flex items-center gap-2.5 hover:bg-sage-700 transition-all shadow-lg shadow-sage-600/20 active:scale-95">
               <span className="material-symbols-outlined text-lg">chat_bubble</span>
               {language === Language.English ? "Consult Assistant" : "諮詢助理"}
            </button>
            <button onClick={handleDownloadWord} className="bg-white border border-stone-200 px-5 py-2.5 rounded-xl text-sm font-bold text-stone-600 hover:bg-stone-50 transition-all active:scale-95">
               <span className="material-symbols-outlined text-lg">description</span>
               {language === Language.English ? "Export Word" : "匯出文件"}
            </button>
          </div>
        </div>

        <div className="p-16 md:p-24 lg:p-32">
          <div ref={contentRef} className="prose prose-stone prose-lg md:prose-2xl max-w-none font-serif leading-relaxed print-only-content">
            <Markdown
              components={{
                h1: (p) => <h1 className="text-6xl font-black text-sage-800 border-b-4 border-sage-600/10 pb-12 mb-20 tracking-tighter text-center italic" {...p} />,
                h2: (p) => {
                  const isBib = isBibliographySection(String(p.children || ""));
                  return (
                    <h2 
                      className={`text-4xl font-bold text-sage-700 mt-24 mb-12 pb-4 border-b-2 tracking-tight ${isBib ? 'border-gold-500' : 'border-sage-200/50'}`} 
                      {...p} 
                    />
                  );
                },
                h3: (p) => <h3 className="text-2xl font-bold text-sage-600 mt-14 mb-6 tracking-tight border-l-4 border-sage-100 pl-6" {...p} />,
                h4: (p) => <h4 className="text-xl font-bold text-sage-500 mt-10 mb-4 italic" {...p} />,
                blockquote: (p) => (
                  <blockquote className="border-l-8 border-gold-500 bg-stone-50/70 py-10 px-14 italic text-stone-800 rounded-r-3xl my-16 shadow-inner font-serif text-3xl leading-relaxed" {...p} />
                ),
                p: (p) => {
                  const text = String(p.children || "");
                  const parts = content.split(/#+ (?:Selected Bibliography|參考書目)/i);
                  const inBib = parts.length > 1 && content.indexOf(text) > content.toLowerCase().indexOf("bibliography");

                  if (inBib && text.length > 30) {
                     return <p className="mb-4 text-xl text-charcoal pl-8 -indent-8 leading-normal font-sans tracking-tight" {...p} />;
                  }

                  // Dropcap only for the very first paragraph of the document
                  const isFirstPara = content.indexOf(text) < 500;
                  return (
                    <p 
                      className={`mb-12 text-charcoal text-justify leading-[1.8] opacity-95 ${isFirstPara ? 'first-letter:text-6xl first-letter:font-bold first-letter:mr-3 first-letter:float-left first-letter:mt-1 first-letter:text-sage-700' : ''}`} 
                      {...p} 
                    />
                  );
                },
                ul: (p) => <ul className="list-disc pl-10 space-y-4 mb-12 marker:text-gold-500" {...p} />,
                ol: (p) => <ol className="list-decimal pl-10 space-y-4 mb-12 marker:text-sage-600 marker:font-bold" {...p} />,
                li: (p) => <li className="text-xl leading-relaxed text-charcoal" {...p} />,
                strong: (p) => <strong className="font-bold text-sage-900 border-b border-gold-500/10" {...p} />,
                em: (p) => <em className="italic text-sage-800" {...p} />
              }}
            >
              {content}
            </Markdown>

            {/* Grounding Sources (Verified Hyperlinks) */}
            {sources && sources.length > 0 && (
              <div className="mt-32 pt-16 border-t-4 border-stone-100 no-print">
                <div className="flex items-center gap-6 mb-12">
                   <h4 className="text-[12px] font-black text-sage-600 uppercase tracking-[0.4em] whitespace-nowrap">
                    Digital Access Grounding
                  </h4>
                  <div className="h-px bg-stone-200 w-full"></div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {sources.map((source, i) => (
                    <a 
                      key={i} 
                      href={source.uri} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="group p-6 bg-white border border-stone-200 rounded-2xl hover:border-sage-400 hover:shadow-xl transition-all flex flex-col justify-between"
                    >
                      <div>
                        <div className="text-[10px] text-gold-600 font-black uppercase tracking-widest mb-2">Primary Access</div>
                        <div className="text-lg font-bold text-sage-800 group-hover:text-sage-600 leading-tight mb-2 line-clamp-2">{source.title}</div>
                      </div>
                      <div className="text-[11px] text-stone-400 font-mono truncate">{source.uri}</div>
                    </a>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
      {showChatSession && <ChatSession contextContent={content} language={language} onClose={() => setShowChatSession(false)} />}
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { StepWizard } from './components/StepWizard';
import { ConfigurationForm } from './components/ConfigurationForm';
import { SelectorGrid } from './components/SelectorGrid';
import { ResultDisplay } from './components/ResultDisplay';
import { ApiKeyInput } from './components/ApiKeyInput';
import { LibraryView } from './components/LibraryView';
import { StudyConfig, KnowledgeLevel, StudyType, Language, ActivityLog, ViewType, LibraryItem } from './types';
import { APPROACHES, TRADITIONS, UI_TEXT, KNOWLEDGE_LEVEL_LABELS, STUDY_TYPE_LABELS } from './constants';
import { generateStudyGuide } from './services/geminiService';

const App: React.FC = () => {
  const [isActivated, setIsActivated] = useState(false);
  const [step, setStep] = useState(1);
  const [language, setLanguage] = useState<Language>(Language.English);
  const [currentView, setCurrentView] = useState<ViewType>('new');

  const [config, setConfig] = useState<StudyConfig>({
    passage: '',
    topic: '',
    knowledgeLevel: KnowledgeLevel.Intermediate,
    studyType: StudyType.Comprehensive,
    duration: 60,
    approaches: [],
    customApproach: '',
    traditions: [],
    language: Language.English,
    autoResearch: true
  });

  const [generatedContent, setGeneratedContent] = useState<string>('');
  const [sources, setSources] = useState<{ uri: string; title: string }[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [logs, setLogs] = useState<ActivityLog[]>([]);
  const [isDirty, setIsDirty] = useState(true);
  const [library, setLibrary] = useState<LibraryItem[]>([]);
  const [currentLibraryItem, setCurrentLibraryItem] = useState<LibraryItem | null>(null);

  // Load library from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('sacred_studies_library');
    if (saved) {
      try {
        setLibrary(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse library", e);
      }
    }
  }, []);

  // Save library to local storage
  useEffect(() => {
    localStorage.setItem('sacred_studies_library', JSON.stringify(library));
  }, [library]);

  useEffect(() => {
    setConfig(prev => ({ ...prev, language }));
  }, [language]);

  const handleConfigChange = (updates: Partial<StudyConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
    setIsDirty(true);
    setCurrentLibraryItem(null);
  };

  const handleNext = async () => {
    if (config.autoResearch && step === 1) {
      setStep(4);
    } else if (step < 4) {
      setStep(step + 1);
    } else {
      setIsGenerating(true);
      setLogs([]);
      try {
        const result = await generateStudyGuide(config, (log) => {
          setLogs(prev => [...prev, log]);
        });
        setGeneratedContent(result.text);
        setSources(result.sources || []);
        setIsDirty(false);
        setCurrentLibraryItem(null);
      } catch (error: any) {
        console.error("Generation Error:", error);
        const errorMsg = error?.message || "";
        if (errorMsg.includes("Requested entity was not found") || errorMsg.includes("API_KEY_INVALID")) {
          await window.aistudio.openSelectKey();
        } else if (errorMsg.includes("429") || errorMsg.includes("Resource has been exhausted")) {
          setGeneratedContent("Quota Exhausted: Your API Key has reached its rate limit.");
        } else {
          setGeneratedContent(`Operational Fault: ${errorMsg || "Generation pipeline interrupted."}`);
        }
      } finally {
        setIsGenerating(false);
      }
    }
  };

  const handleSaveToLibrary = () => {
    if (!generatedContent) return;

    const newItem: LibraryItem = {
      id: crypto.randomUUID(),
      title: config.topic || config.passage,
      content: generatedContent,
      sources: sources,
      config: { ...config },
      timestamp: new Date()
    };

    setLibrary(prev => [...prev, newItem]);
    setCurrentLibraryItem(newItem);
  };

  const handleOpenLibraryItem = (item: LibraryItem) => {
    setCurrentLibraryItem(item);
    setGeneratedContent(item.content);
    setSources(item.sources);
    setConfig(item.config);
    setStep(4);
    setCurrentView('new');
    setIsDirty(false);
  };

  const handleDeleteLibraryItem = (id: string) => {
    setLibrary(prev => prev.filter(item => item.id !== id));
    if (currentLibraryItem?.id === id) {
      setCurrentLibraryItem(null);
    }
  };

  const t = UI_TEXT;
  const langKey = language === Language.English ? 'en' : 'zh';

  if (!isActivated) {
    return <ApiKeyInput onActivated={() => setIsActivated(true)} />;
  }

  const getSelectedLabels = (items: any[], selectedIds: string[]) => {
    if (config.autoResearch) return [t.latestResearch[langKey]];
    return selectedIds.map(id => {
      const item = items.find(i => i.id === id);
      if (id === 'custom' && config.customApproach) return config.customApproach;
      return item ? item.label[langKey] : id;
    }).filter(Boolean);
  };

  return (
    <div className="flex h-screen w-full overflow-hidden bg-white">
      {/* Aside - Navigation */}
      <aside className="hidden w-64 flex-col border-r border-stone-200 bg-white md:flex">
        <div className="flex h-full flex-col justify-between p-4">
          <div className="flex flex-col gap-6">
            <div className="flex items-center gap-3 px-2">
              <div className="flex items-center justify-center size-10 rounded-xl bg-primary text-white shadow-lg shadow-primary/20">
                <span className="text-xl font-bold">S</span>
              </div>
              <h1 className="text-xl font-bold leading-normal tracking-tight text-text-main">Sacred Studies</h1>
            </div>
            <nav className="flex flex-col gap-2">
              <button 
                onClick={() => setCurrentView('dashboard')}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors w-full text-left ${currentView === 'dashboard' ? 'bg-primary/10 text-primary' : 'text-stone-500 hover:bg-stone-100'}`}
              >
                <span className="material-symbols-outlined" style={{fontSize: '24px'}}>dashboard</span>
                <span className="text-sm font-semibold">{t.dashboard[langKey]}</span>
              </button>
              <button 
                onClick={() => setCurrentView('new')}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors w-full text-left ${currentView === 'new' ? 'bg-primary/10 text-primary' : 'text-stone-500 hover:bg-stone-100'}`}
              >
                <span className="material-symbols-outlined" style={{fontSize: '24px'}}>edit_document</span>
                <span className="text-sm font-semibold">{t.generatePaper[langKey]}</span>
              </button>
              <button 
                onClick={() => setCurrentView('library')}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors w-full text-left ${currentView === 'library' ? 'bg-primary/10 text-primary' : 'text-stone-500 hover:bg-stone-100'}`}
              >
                <span className="material-symbols-outlined" style={{fontSize: '24px'}}>library_books</span>
                <span className="text-sm font-semibold">{t.myLibrary[langKey]}</span>
              </button>
              <button 
                onClick={() => setCurrentView('settings')}
                className={`flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors w-full text-left ${currentView === 'settings' ? 'bg-primary/10 text-primary' : 'text-stone-500 hover:bg-stone-100'}`}
              >
                <span className="material-symbols-outlined" style={{fontSize: '24px'}}>settings</span>
                <span className="text-sm font-semibold">{t.settings[langKey]}</span>
              </button>
            </nav>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex flex-1 flex-col overflow-y-auto bg-[#f8f7f4] relative">
        <Header language={language} onToggleLanguage={() => setLanguage(l => l === Language.English ? Language.TraditionalChinese : Language.English)} />

        <div className="w-full max-w-4xl mx-auto px-6 pb-32">
          {currentView === 'new' ? (
            <>
              <div className="no-print pt-4">
                <StepWizard currentStep={step} totalSteps={4} onStepClick={setStep} language={language} />
              </div>

              <div className="mt-4">
                {step === 1 && <ConfigurationForm config={config} onChange={handleConfigChange} language={language} />}
                {step === 2 && !config.autoResearch && (
                  <SelectorGrid
                    title={t.selectApproachesTitle[langKey]}
                    subtitle={t.selectApproachesSub[langKey]}
                    items={APPROACHES}
                    selectedIds={config.approaches}
                    onToggle={(id) => handleConfigChange({ approaches: config.approaches.includes(id) ? config.approaches.filter(a => a !== id) : [...config.approaches, id] })}
                    language={language}
                    customInputId="custom"
                    customInputValue={config.customApproach}
                    onCustomInputChange={(val) => handleConfigChange({ customApproach: val })}
                  />
                )}
                {step === 3 && !config.autoResearch && (
                  <SelectorGrid
                    title={t.selectTraditionsTitle[langKey]}
                    subtitle={t.selectTraditionsSub[langKey]}
                    items={TRADITIONS}
                    selectedIds={config.traditions}
                    onToggle={(id) => handleConfigChange({ traditions: config.traditions.includes(id) ? config.traditions.filter(t => t !== id) : [...config.traditions, id] })}
                    language={language}
                  />
                )}
                {step === 4 && (
                  <div className="space-y-12 animate-fade-in">
                    <div className="bg-white p-10 rounded-3xl border border-stone-200 shadow-soft max-w-4xl mx-auto no-print">
                      <h2 className="font-serif text-3xl font-bold text-primary mb-8 text-center border-b border-stone-100 pb-6 tracking-tight">{t.reviewConfig[langKey]}</h2>

                      <div className="space-y-8">
                        <dl className="grid grid-cols-1 md:grid-cols-2 gap-8 text-base">
                          <div className="bg-stone-50 p-6 rounded-2xl border border-stone-100">
                            <dt className="text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-2">{t.passageLabel[langKey]}</dt>
                            <dd className="font-serif text-2xl font-bold text-text-main">{config.passage || "-"}</dd>
                          </div>
                          <div className="bg-stone-50 p-6 rounded-2xl border border-stone-100">
                            <dt className="text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-2">{t.topicLabel[langKey]}</dt>
                            <dd className="font-serif text-2xl font-bold text-text-main">{config.topic || "-"}</dd>
                          </div>
                        </dl>

                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                          <div className="border border-stone-100 p-5 rounded-xl bg-white">
                            <dt className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-1">{t.knowledgeLabel[langKey]}</dt>
                            <dd className="font-bold text-primary">{KNOWLEDGE_LEVEL_LABELS[config.knowledgeLevel][langKey]}</dd>
                          </div>
                          <div className="border border-stone-100 p-5 rounded-xl bg-white">
                            <dt className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-1">{t.typeLabel[langKey]}</dt>
                            <dd className="font-bold text-primary">{STUDY_TYPE_LABELS[config.studyType][langKey]}</dd>
                          </div>
                          <div className="border border-stone-100 p-5 rounded-xl bg-white">
                            <dt className="text-[9px] font-bold text-stone-400 uppercase tracking-[0.2em] mb-1">{t.durationLabel[langKey]}</dt>
                            <dd className="font-bold text-primary">{config.duration} {t.minutes[langKey]}</dd>
                          </div>
                        </div>

                        <div className="space-y-4">
                          <div className="bg-primary/5 p-6 rounded-2xl border border-primary/10">
                            <dt className="text-[10px] font-bold text-primary uppercase tracking-widest mb-3">{t.stepApproaches[langKey]}</dt>
                            <dd className="flex flex-wrap gap-2">
                              {getSelectedLabels(APPROACHES, config.approaches).map((label, i) => (
                                <span key={i} className="px-3 py-1 bg-white border border-primary/20 text-primary rounded-full text-xs font-bold shadow-sm">
                                  {label}
                                </span>
                              ))}
                            </dd>
                          </div>

                          <div className="bg-primary/5 p-6 rounded-2xl border border-primary/10">
                            <dt className="text-[10px] font-bold text-primary uppercase tracking-widest mb-3">{t.stepTraditions[langKey]}</dt>
                            <dd className="flex flex-wrap gap-2">
                              {config.autoResearch ? (
                                <span className="px-3 py-1 bg-white border border-primary/20 text-primary rounded-full text-xs font-bold shadow-sm">
                                  {t.latestResearch[langKey]}
                                </span>
                              ) : getSelectedLabels(TRADITIONS, config.traditions).map((label, i) => (
                                <span key={i} className="px-3 py-1 bg-white border border-primary/20 text-primary rounded-full text-xs font-bold shadow-sm">
                                  {label}
                                </span>
                              ))}
                            </dd>
                          </div>
                        </div>
                      </div>
                    </div>
                    <ResultDisplay 
                      content={generatedContent} 
                      isGenerating={isGenerating} 
                      language={language} 
                      logs={logs} 
                      sources={sources} 
                      onSave={handleSaveToLibrary}
                      isSaved={!!currentLibraryItem}
                    />
                  </div>
                )}
              </div>
            </>
          ) : currentView === 'library' ? (
            <div className="mt-12">
              <div className="mb-12 border-b border-stone-200 pb-8">
                <h2 className="font-serif text-4xl font-bold text-text-main mb-2 tracking-tight">{t.myLibrary[langKey]}</h2>
                <p className="text-stone-500 font-medium">{language === Language.English ? "Browse and consult your saved theological manuscripts." : "瀏覽並諮詢您儲存的神學手稿。"}</p>
              </div>
              <LibraryView 
                library={library} 
                language={language} 
                onOpenItem={handleOpenLibraryItem} 
                onDeleteItem={handleDeleteLibraryItem}
              />
            </div>
          ) : (
            <div className="flex flex-col items-center justify-center py-32 text-stone-400">
              <span className="material-symbols-outlined text-6xl mb-4">construction</span>
              <p className="text-xl font-bold uppercase tracking-widest">{language === Language.English ? "Feature Under Construction" : "功能開發中"}</p>
            </div>
          )}
        </div>

        {/* Updated Footer Navigation with translated button text */}
        <footer className="bg-white border-t border-stone-200 fixed bottom-0 left-0 md:left-64 right-0 z-40 py-6 no-print shadow-[0_-4px_20px_rgba(0,0,0,0.03)] backdrop-blur-md bg-white/90">
          <div className="max-w-4xl mx-auto px-6 flex justify-between items-center">
            {currentView === 'new' ? (
              <>
                <button 
                  onClick={() => setStep(config.autoResearch && step === 4 ? 1 : step - 1)} 
                  disabled={step === 1 || isGenerating} 
                  className="px-6 py-3 rounded-xl font-bold text-stone-500 hover:text-primary transition-all disabled:opacity-0 flex items-center gap-2"
                >
                  <span className="material-symbols-outlined">arrow_back</span>
                  {t.back[langKey]}
                </button>
                <div className="flex gap-4">
                  <button
                    onClick={handleNext}
                    disabled={!config.passage || isGenerating || (!isDirty && generatedContent !== '')}
                    className={`px-10 py-4 rounded-xl font-bold text-lg text-white shadow-lg transition-all transform hover:-translate-y-0.5 active:translate-y-0 flex items-center gap-3 ${
                      !config.passage || isGenerating || (!isDirty && generatedContent !== '')
                        ? 'bg-stone-300 shadow-none grayscale'
                        : 'bg-text-main hover:bg-black shadow-text-main/20'
                    }`}
                  >
                    {isGenerating ? t.synthesizing[langKey] : (
                      <span className="flex items-center gap-2">
                        {step === 1 ? (config.autoResearch ? t.generate[langKey] : t.nextApproaches[langKey]) : 
                         step === 2 ? t.nextTraditions[langKey] : 
                         step === 3 ? t.nextReview[langKey] : 
                         t.generate[langKey]}
                        <span className="material-symbols-outlined">arrow_forward</span>
                      </span>
                    )}
                  </button>
                </div>
              </>
            ) : (
              <div className="w-full flex justify-center">
                <button 
                  onClick={() => setCurrentView('new')}
                  className="bg-primary text-white px-12 py-4 rounded-xl font-bold text-lg shadow-lg hover:shadow-primary/30 transition-all flex items-center gap-3"
                >
                  <span className="material-symbols-outlined">add_circle</span>
                  {t.newAnalysis[langKey]}
                </button>
              </div>
            )}
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;
